<script setup lang="ts">import { computed } from 'vue';import type { Agent,NpcStatus } from '../domain/types';import { npcStatusText,visualProfile } from '../domain/visual';const p=defineProps<{agent:Agent;status?:NpcStatus;active?:boolean;compact?:boolean}>();const visual=computed(()=>visualProfile(p.agent.id));</script>
<template><div class="npc" :class="[status||'idle',{active,compact}]" :aria-label="`${agent.name}，${npcStatusText[status||'idle']}`"><div class="npc-bubble" v-if="status&&status!=='idle'">{{npcStatusText[status]}}</div><div class="npc-figure" :style="{'--robe':visual.color,'--accent':visual.accent}"><span class="npc-hair"></span><span class="npc-head"><i></i><b></b></span><span class="npc-body"><em>{{visual.glyph}}</em></span><span class="npc-accessory" aria-hidden="true">{{visual.accessory.slice(0,1)}}</span></div><div class="npc-name">{{agent.name}}</div></div></template>
